class Solution:
    def minMaxSums(self, nums, k):
        n = len(nums)
        MOD = 10 ** 9 + 7
        total = 0
        for mask in range(1, 1 << n):
            size = bin(mask).count('1')
            if size > k:
                continue
            vals = [nums[i] for i in range(n) if mask & (1 << i)]
            total += max(vals) + min(vals)
        return total % MOD

