class Solution:
    def minMaxSums(self, nums, k):
        MOD = 10 ** 9 + 7
        nums = sorted(nums)
        n = len(nums)
        fact = [1] * (n + 1)
        for i in range(1, n + 1):
            fact[i] = fact[i - 1] * i % MOD
        invfact = [1] * (n + 1)
        invfact[n] = pow(fact[n], MOD - 2, MOD)
        for i in range(n - 1, -1, -1):
            invfact[i] = invfact[i + 1] * (i + 1) % MOD

        def comb(a, b):
            if b < 0 or b > a:
                return 0
            return fact[a] * invfact[b] % MOD * invfact[a - b] % MOD

        ans = 0
        for i in range(n):
            max_count = 0
            for j in range(min(k - 1, i) + 1):
                max_count = (max_count + comb(i, j)) % MOD
            larger = n - 1 - i
            min_count = 0
            for j in range(min(k - 1, larger) + 1):
                min_count = (min_count + comb(larger, j)) % MOD
            ans = (ans + nums[i] * (max_count + min_count)) % MOD
        return ans

