var minMaxSums = function(nums, k) {
    const MOD = 1000000007n;
    const sorted = nums.slice().sort((a, b) => a - b);
    const n = sorted.length;
    const fact = new Array(n + 1);
    fact[0] = 1n;
    for (let i = 1; i <= n; i++) fact[i] = (fact[i - 1] * BigInt(i)) % MOD;
    function power(a, b, m) {
        a %= m;
        let r = 1n;
        while (b > 0n) {
            if (b & 1n) r = (r * a) % m;
            a = (a * a) % m;
            b >>= 1n;
        }
        return r;
    }
    const invfact = new Array(n + 1);
    invfact[n] = power(fact[n], MOD - 2n, MOD);
    for (let i = n - 1; i >= 0; i--) invfact[i] = (invfact[i + 1] * BigInt(i + 1)) % MOD;
    function comb(a, b) {
        if (b < 0 || b > a) return 0n;
        return (fact[a] * invfact[b] % MOD) * invfact[a - b] % MOD;
    }
    let ans = 0n;
    for (let i = 0; i < n; i++) {
        let maxCount = 0n;
        const lim1 = Math.min(k - 1, i);
        for (let j = 0; j <= lim1; j++) maxCount = (maxCount + comb(i, j)) % MOD;
        const larger = n - 1 - i;
        let minCount = 0n;
        const lim2 = Math.min(k - 1, larger);
        for (let j = 0; j <= lim2; j++) minCount = (minCount + comb(larger, j)) % MOD;
        ans = (ans + BigInt(sorted[i]) * (maxCount + minCount)) % MOD;
    }
    return Number(ans);
};
